// React — enable via prop
<VeltComments visibilityOptionDropdown={true} />

// React — enable/disable programmatically
const { client } = useVeltClient();
useEffect(() => {
  if (!client) return;
  const commentElement = client.getCommentElement();
  commentElement.enableVisibilityOptionDropdown();
  return () => commentElement.disableVisibilityOptionDropdown();
}, [client]);

// React — subscribe to the event
const onVisibilityOptionClicked = useCommentEventCallback(
  'visibilityOptionClicked',
  (event: VisibilityOptionClickedEvent) => {
    console.log(event.visibility); // 'public' | 'private'
  }
);

// Other Frameworks — enable/disable programmatically
const commentElement = Velt.getCommentElement();
commentElement.enableVisibilityOptionDropdown();
// ...
commentElement.disableVisibilityOptionDropdown();
